  select $_hc$[{"id":"artic-crazy-quilt-with-animals-181720","title":"'Crazy Quilt' with Animals","maker":"Florence Elizabeth Marvin","culture":"Brooklyn Heights","country":null,"region":null,"date_display":"1886","category":"textile","image_url":"https://www.artic.edu/iiif/2/20692004-784b-0c7b-9a15-0db2dd6e83e4/full/843,/0/default.jpg","source_name":"Art Institute of Chicago","source_url":"https://www.artic.edu/artworks/181720","license":"Public domain / Art Institute of Chicago","hook":"A textile where bird, cat, and deer give the color a sharper pulse.","story":"'Crazy Quilt' with Animals enters the collection record by Florence Elizabeth Marvin, from Brooklyn Heights, and dated 1886. The bird, cat, and deer turn small details into the way into the piece. For the archive, 'Crazy Quilt' with Animals works as a vivid piece of material culture.","why_it_matters":"'Crazy Quilt' with Animals rewards attention without announcing its importance.","latitude":37.0902,"longitude":-95.7129,"week_key":"full-archive-2026-W01"},{"id":"artic-basket-35716","title":"Basket","maker":null,"culture":"England","country":null,"region":null,"date_display":"c. 1645","category":"textile","image_url":"https://www.artic.edu/iiif/2/8c7ef82e-1cb1-9dc5-ff8a-dab29259049b/full/843,/0/default.jpg","source_name":"Art Institute of Chicago","source_url":"https://www.artic.edu/artworks/35716","license":"Public domain / Art Institute of Chicago","hook":"Basket makes a small encounter feel carefully staged.","story":"Basket is recorded from England, and dated c. 1645. Nothing about Basket feels accidental; the form asks to be read slowly. For the archive, Basket works as a vivid piece of material culture.","why_it_matters":"Basket shows how handwork can preserve memory without losing visual force.","latitude":52.3555,"longitude":-1.1743,"week_key":"full-archive-2026-W01"},{"id":"artic-cabinet-or-box-depicting-scenes-from-the-old-testament-10503","title":"Cabinet or Box Depicting Scenes from the Old Te